package main

import (
	"flag"
	"fmt"
	"go/parser"
	"go/token"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"text/template"
)

var (
	enterprisePath = flag.String("enterprise", "../grafana-enterprise", "Where is the Grafana Enterprise Git repo?")
	outputPath     = flag.String("output", "./pkg/extensions/", "Where is the Extensions directory in the Grafana OSS repo?")
)

func init() {
	flag.Parse()
}

func main() {
	if err := run(); err != nil {
		fmt.Println(err)
		os.Exit(1)
	}
}

var fileTemplate = template.Must(template.New("main").Parse(`//go:build never
// +build never

// Code generated by scripts/ci/generate-enterprise-imports; DO NOT EDIT.

package extensions
{{- if .}}

import (
{{- range .}}
	_ "{{.}}"
{{- end}}
)
{{- end}}
`))

func run() error {
	srcDir := filepath.Join(*enterprisePath, "src")

	if _, err := os.Stat(srcDir); os.IsNotExist(err) {
		fmt.Printf("enterprise source directory %s does not exist, skipping\n", srcDir)
		return nil
	}

	regularImports := make(map[string]struct{})
	testImports := make(map[string]struct{})

	err := filepath.Walk(srcDir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}
		if info.IsDir() {
			if info.Name() == "vendor" {
				return filepath.SkipDir
			}
			return nil
		}
		if !strings.HasSuffix(path, ".go") {
			return nil
		}

		fset := token.NewFileSet()
		f, parseErr := parser.ParseFile(fset, path, nil, parser.ImportsOnly)
		if parseErr != nil {
			return nil
		}

		isTest := strings.HasSuffix(path, "_test.go")

		for _, imp := range f.Imports {
			importPath := strings.Trim(imp.Path.Value, `"`)

			// Skip stdlib packages (no dot in first path element)
			if !strings.Contains(strings.SplitN(importPath, "/", 2)[0], ".") {
				continue
			}

			// Skip grafana-enterprise internal packages
			if strings.HasPrefix(importPath, "github.com/grafana/grafana-enterprise/") ||
				strings.HasPrefix(importPath, "github.com/grafana/grafana/pkg/extensions/") {
				continue
			}

			if isTest {
				testImports[importPath] = struct{}{}
			} else {
				regularImports[importPath] = struct{}{}
			}
		}
		return nil
	})
	if err != nil {
		return fmt.Errorf("walking enterprise source: %w", err)
	}

	// Imports already in the regular set don't need to be in the test set
	for imp := range regularImports {
		delete(testImports, imp)
	}

	if err := writeFile(filepath.Join(*outputPath, "enterprise_imports.go"), fileTemplate, sortedSlice(regularImports)); err != nil {
		return err
	}
	if err := writeFile(filepath.Join(*outputPath, "enterprise_imports_test.go"), fileTemplate, sortedSlice(testImports)); err != nil {
		return err
	}

	return nil
}

func sortedSlice(m map[string]struct{}) []string {
	s := make([]string, 0, len(m))
	for k := range m {
		s = append(s, k)
	}
	sort.Strings(s)
	return s
}

func writeFile(path string, tmpl *template.Template, imports []string) error {
	f, err := os.Create(path)
	if err != nil {
		return fmt.Errorf("creating %s: %w", path, err)
	}
	defer f.Close()
	return tmpl.Execute(f, imports)
}
